import { useEffect, useState } from "react";
import axios from "axios";

function Book() {
  const user = JSON.parse(localStorage.getItem("user"));

  const [doctors, setDoctors] = useState([]);

  const [data, setData] = useState({
    patientId: user._id,
    patientName: user.name,
    patientEmail: user.email,
    doctorName: "",
    date: "",
    time: "",
    problem: "",
    symptoms: "",
    phone: "",
    isEmergency: false
  });

  useEffect(() => {
    axios.get("http://localhost:5000/api/users/doctors")
      .then(res => setDoctors(res.data));
  }, []);

  const handleBook = async () => {
    const res = await axios.post(
      "http://localhost:5000/api/appointments/book",
      data
    );

    alert(res.data.message);
  };

  return (
    <div className="main">
      <h2>Book Appointment</h2>

      <select onChange={e => setData({...data, doctorName: e.target.value})}>
        <option>Select Doctor</option>
        {doctors.map(doc => (
          <option key={doc._id} value={doc.name}>
            {doc.name} ({doc.specialization})
          </option>
        ))}
      </select>

      <input type="date"
        onChange={e => setData({...data, date: e.target.value})} />

      <input placeholder="Time"
        onChange={e => setData({...data, time: e.target.value})} />

      <input placeholder="Problem"
        onChange={e => setData({...data, problem: e.target.value})} />

      <input placeholder="Symptoms"
        onChange={e => setData({...data, symptoms: e.target.value})} />

      <input placeholder="Phone"
        onChange={e => setData({...data, phone: e.target.value})} />

      <label>
        <input type="checkbox"
          onChange={e => setData({...data, isEmergency: e.target.checked})} />
        Emergency
      </label>

      <button onClick={handleBook}>Book</button>
    </div>
  );
}

export default Book;
